// client/src/components/CatCard.js
import React from 'react';
import { Link } from 'react-router-dom';
import { LevelIcon, FishingIcon, HuntingIcon } from './Icons';

const CatCard = ({ cat }) => {
  // Определение класса стиля в зависимости от редкости кошки
  const getRarityClass = () => {
    switch (cat.rarity) {
      case 'common': return 'cat-common';
      case 'uncommon': return 'cat-uncommon';
      case 'rare': return 'cat-rare';
      case 'epic': return 'cat-epic';
      case 'legendary': return 'cat-legendary';
      default: return 'cat-common';
    }
  };

  // Перевод редкости на русский
  const getRarityText = () => {
    switch (cat.rarity) {
      case 'common': return 'Обычная';
      case 'uncommon': return 'Необычная';
      case 'rare': return 'Редкая';
      case 'epic': return 'Эпическая';
      case 'legendary': return 'Легендарная';
      default: return 'Обычная';
    }
  };

  return (
    <Link to={`/cats/${cat._id}`}>
      <div className={`cat-card ${getRarityClass()} mb-4`}>
        <div className="flex justify-between items-start">
          <div>
            <h3 className="text-lg font-bold">{cat.name}</h3>
            <p className="text-sm text-gray-600">{cat.breed}</p>
            <p className="text-xs">{getRarityText()}</p>
          </div>

          <div className="flex items-center bg-gray-100 rounded-full px-2 py-1">
            <LevelIcon className="w-4 h-4 mr-1 text-yellow-500" />
            <span className="text-sm font-bold">{cat.level}</span>
          </div>
        </div>

        <div className="mt-3">
          <div className="flex items-center mb-1">
            <FishingIcon className="w-4 h-4 mr-2 text-blue-500" />
            <div className="bg-gray-200 h-2 rounded-full flex-grow">
              <div 
                className="bg-blue-500 h-2 rounded-full" 
                style={{ width: `${Math.min(cat.stats.fishing * 10, 100)}%` }}
              ></div>
            </div>
            <span className="ml-2 text-xs">{cat.stats.fishing}</span>
          </div>

          <div className="flex items-center">
            <HuntingIcon className="w-4 h-4 mr-2 text-green-500" />
            <div className="bg-gray-200 h-2 rounded-full flex-grow">
              <div 
                className="bg-green-500 h-2 rounded-full" 
                style={{ width: `${Math.min(cat.stats.hunting * 10, 100)}%` }}
              ></div>
            </div>
            <span className="ml-2 text-xs">{cat.stats.hunting}</span>
          </div>
        </div>

        <div className="mt-3 text-xs text-right">
          <span className="text-gray-500">Опыт: {cat.experience}/{cat.level * 100}</span>
        </div>
      </div>
    </Link>
  );
};

export default CatCard;
